import (
	context "context"
	fern "github.com/union-query-parameters/fern"
	fernclient "github.com/union-query-parameters/fern/client"
)

client := fernclient.NewClient()
response, err := client.Events.Subscribe(
	context.TODO(),
	&fern.SubscribeEventsRequest{
		EventType: &fern.EventTypeParam{
			EventTypeEnum: fern.EventTypeEnumGroupCreated,
		},
		Tags: &fern.StringOrListParam{
			String: "tags",
		},
	},
)
